import React, { useState, useEffect } from 'react';
import { Routes, Route, Navigate, useLocation } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import Navbar from './components/Navbar';
import BottomNavigation from './components/BottomNavigation';
import Login from './components/Login';

// Pages
import Home from './pages/Home';
import Medicines from './pages/Medicines';
import Availability from './pages/Availability';
import Appointments from './pages/Appointments';
import Schedule from './pages/Schedule';
import Profile from './pages/Profile';
import Settings from './pages/Settings';
import VideoCallPage from './pages/VideoCallPage';
import AudioCallPage from './pages/AudioCallPage';

function App() {
  const { i18n } = useTranslation();
  const location = useLocation();
  
  // Pages that should not show navigation
  const fullScreenPages = ['/video-call', '/audio-call'];
  const isFullScreenPage = fullScreenPages.includes(location.pathname);
  
  // Set document direction based on language
  React.useEffect(() => {
    document.documentElement.dir = i18n.dir();
  }, [i18n.language]);

  // Full screen pages (like video call) - no navigation
  if (isFullScreenPage) {
    return (
      <div className="App min-h-screen">
        <Routes>
          <Route path="/video-call" element={<VideoCallPage />} />
          <Route path="/audio-call" element={<AudioCallPage />} />
        </Routes>
      </div>
    );
  }

  // Regular pages with navigation
  return (
    <div className="App min-h-screen bg-gray-50">
      <div className="flex flex-col min-h-screen">
        <Navbar />
        <main
          className="flex-1 pt-16"
          style={{
            // Reserve space for the fixed bottom navigation so content is never hidden
            // Increased to 96px to ensure long cards and buttons are not covered
            paddingBottom: 'calc(96px + env(safe-area-inset-bottom, 0px))'
          }}
        >
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/home" element={<Home />} />
            <Route path="/availability" element={<Availability />} />
            <Route path="/appointments" element={<Appointments />} />
            <Route path="/medicines" element={<Medicines />} />
            <Route path="/schedule" element={<Schedule />} />
            <Route path="/profile" element={<Profile />} />
            <Route path="/settings" element={<Settings />} />
            <Route path="*" element={<Navigate to="/" replace />} />
          </Routes>
        </main>
        {/* Global spacer to prevent overlap with fixed bottom nav */}
        <div
          aria-hidden="true"
          style={{ height: 'calc(96px + env(safe-area-inset-bottom, 0px))' }}
        />
        <BottomNavigation />
      </div>
    </div>
  );
}

export default App;
